-- First, clean up any existing duplicates (keep only the most recent)
DELETE FROM agents
WHERE name = 'Discipline Automation Agent'
  AND id NOT IN (
    SELECT id
    FROM (
      SELECT
        id,
        ROW_NUMBER() OVER (PARTITION BY name ORDER BY created_at DESC) as rn
      FROM agents
      WHERE name = 'Discipline Automation Agent'
    ) ranked
    WHERE rn = 1
  );

-- Check if agent already exists (after cleanup)
