-- Insert model assignment for the agent
INSERT INTO agent_models (
  agent_id,
  model_id,
  assignment_type,
  priority,
  temperature,
  max_tokens,
  assigned_at,
  assigned_by,
  reason,
  is_active
) VALUES (
  'Discipline Automation Agent',
  'Z.ai: GLM 5.1',  -- Highest capability GLM model for complex automation
  'primary',
  1,
  0.7,
  8192,  -- Higher token limit for complex automation tasks
  NOW(),
  'atlas-agent-creator',
  'Primary GLM 5.1 model for complex discipline automation, cross-platform orchestration, and multi-company coordination requiring advanced reasoning capabilities',
  true
) ON CONFLICT (agent_id, assignment_type) DO NOTHING;

