-- Insert activity log entry (only if agent was created)
INSERT INTO activity_log (
  id,
  company_id,
  actor_type,
  actor_id,
  action,
  entity_type,
  entity_id,
  agent_id,
  details,
  created_at
)
SELECT
  gen_random_uuid(),
  (SELECT id FROM companies WHERE name = 'PromptForge AI'),
  'system',
  'atlas-agent-creator',
  'create',
  'agent',
  a.id,
  a.id,
  '{
    "description": "Discipline Automation Agent created and registered in Paperclip ecosystem",
    "capabilities": ["automation", "orchestration", "cross-platform", "multi-company"],
    "integration_points": 10,
    "skills": [
      "discipline-automation-orchestration",
      "knowledge-synthesis-management",
      "project-intelligence-analysis",
      "issue-generation-optimization",
      "multi-company-orchestration",
      "learning-integration-coordination",
      "ui-ux-design-coordination",
      "skill-validation-remediation"
    ]
  }'::jsonb,
  NOW()
FROM agents a
WHERE a.name = 'Discipline Automation Agent'
  AND a.created_at >= NOW() - INTERVAL '1 minute'
ORDER BY a.created_at DESC
LIMIT 1;

-- Verify agent creation
SELECT
  a.id,
  a.name,
  a.role,
  a.title,
  a.status,
  c.name as company_name,
  a.capabilities,
  a.created_at
FROM agents a
JOIN companies c ON a.company_id = c.id
WHERE a.name = 'Discipline Automation Agent'
ORDER BY a.created_at DESC
LIMIT 1;

COMMIT;
